private int dp(int position, int speed, int target, Map<String, Integer> memo) {
    if (Math.abs(position) > 2 * target) {
        return target + 1;
    }
    if (position == target) {
        return speed == 1 ? 0 : 1;
    }
    String key = position + "," + speed;
